return items.map(item => {
  const body = item.json?.body || {};
  const ch = body.channel_type;
  let n = {
    botId: body.bot_id || null, channel: ch || null,
    conversationId: body.conversation_id || null,
    threadId: body.external_thread_id || null,
    user: { id: null, name: null, username: null },
    message: { id: null, text: null, type: body.message_type || null, timestamp: null },
    raw: body.raw || null
  };
  if (ch === 'telegram') {
    n.user.id = body.user?.external_id || body.raw?.message?.from?.id || null;
    n.user.name = body.user?.name || [body.raw?.message?.from?.first_name, body.raw?.message?.from?.last_name].filter(Boolean).join(' ') || null;
    n.user.username = body.user?.username || body.raw?.message?.from?.username || null;
    n.message.id = body.raw?.message?.message_id || null;
    n.message.text = body.raw?.message?.text || body.text || null;
    n.message.timestamp = body.raw?.message?.date || null;
  }
  if (ch === 'whatsapp') {
    n.user.id = body.user?.external_id || body.user?.wa_id || body.raw?.message?.from || null;
    n.user.name = body.user?.name || body.user?.profile?.name || body.raw?.contact?.profile?.name || null;
    n.message.id = body.wa_message_id || body.raw?.message?.id || null;
    n.message.text = body.raw?.message?.text?.body || body.text || null;
    n.message.timestamp = body.raw?.message?.timestamp || null;
  }
  return { json: n };
});

const payload = $('Normalize Payload').first().json;
const config = $('Fetch Bot Config').first().json;
return [{
  json: {
    conversation_id: payload.conversationId,
    bot_id: payload.botId,
    user_message: payload.message.text,
    channel_type: payload.channel,
    user_name: payload.user.name || '',
    user_id: payload.user.id || payload.conversationId,
    system_prompt: config.system_prompt || 'You are a helpful customer service assistant.',
    bot_name: config.name || 'AI Assistant'
  }
}];

const forced = $('Fetch History').first().json.contact_status?.forcedIntent || null;
let classified = forced;
if (!forced) {
  try { classified = ($('Intent Classifier').first().json.text || '').trim().toLowerCase(); } catch(e) { classified = ''; }
}
const valid = ["engagement.greeting_new","engagement.greeting_return","engagement.time_inquiry","discovery.program_detail","discovery.schedule_location","discovery.tutor_profile","discovery.curriculum","evaluation.pricing_inquiry","evaluation.objection_price","evaluation.objection_compare","evaluation.objection_risk","evaluation.objection_authority","evaluation.objection_urgency","conversion.soft","conversion.transaction","conversion.confirm","retention.complaint_service","retention.complaint_refund","retention.progress_inquiry","retention.reschedule"];
const intent = valid.includes(classified) ? classified : 'discovery.program_detail';
return [{ json: { intent, wasForced: !!forced } }];

const ctx = $('Prepare Context').first().json;
const intentData = $('Merge Intent').first().json;
const hist = $('Fetch History').first().json;
let templates = [];
try { templates = $input.first().json?.templates || []; } catch(e) {}
let templates_xml = 'Tidak ada template khusus. Gunakan gaya bahasa natural.';
if (templates.length > 0) {
  templates_xml = templates.map(t =>
    '<TEMPLATE name="' + (t.name||'') + '" intent="' + (t.sub_category||t.category||'general') + '">\n' + t.content + '\n</TEMPLATE>'
  ).join('\n\n');
}
return [{
  json: {
    ...ctx, intent: intentData.intent, wasForced: intentData.wasForced,
    history: hist.history_text || '', time_context: hist.time_context || '',
    greeting_word: hist.greeting_word || '',
    prompt_instruction: hist.contact_status?.promptInstruction || '',
    templates_xml, templates_count: templates.length,
    rag_search_query: ctx.user_message, kb_type: 'faq'
  }
}];

