return items.map(item => {
  let content = String(item.json.output || item.json.response || item.json.text || '');
  content = content
    .replace(/<thinking[\s\S]*?<\/thinking>/gi, '')
    .replace(/<analysis[\s\S]*?<\/analysis>/gi, '')
    .replace(/<reasoning[\s\S]*?<\/reasoning>/gi, '')
    .replace(/<\/?[^>]+>/g, '')
    .replace(/\n{3,}/g, '\n\n').trim();
  if (!content) content = 'Maaf Kak, saya sedang mengalami kendala teknis. Mohon coba lagi ya 🙏';
  item.json.content = content;
  return item;
});

